import{_ as l,o as t,c as e,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F03: 合約負債與營收能見度 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3105_穩懋/20260503/F03_合約負債與營收能見度.md","filePath":"審計報告庫/財務審計/3105_穩懋/20260503/F03_合約負債與營收能見度.md"}'),i={name:"審計報告庫/財務審計/3105_穩懋/20260503/F03_合約負債與營收能見度.md"};function o(n,a,s,h,d,_){return t(),e("div",null,[...a[0]||(a[0]=[r('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f03-合約負債與營收能見度-財務審計專家-審計報告" tabindex="-1">F03: 合約負債與營收能見度 - 財務審計專家 審計報告 <a class="header-anchor" href="#f03-合約負債與營收能見度-財務審計專家-審計報告" aria-label="Permalink to &quot;F03: 合約負債與營收能見度 - 財務審計專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>合約負債與未來收入的變動關係為何？訂單轉化為實質營收的速度是否出現停滯？透過測算合約負債與營收的比例及轉化時間，判定未來營運動能的含金量。</p></blockquote><h2 id="🎯-專家直斷-58-字" tabindex="-1">🎯 專家直斷（58 字） <a class="header-anchor" href="#🎯-專家直斷-58-字" aria-label="Permalink to &quot;🎯 專家直斷（58 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：合約負債觸底強彈 +67.6% 與營收趨勢一致，惟佔季營收僅 7-12%（能見度 8 天），屬短交期常態非訂單動能不足。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至 2025 年最新公開數據</li></ul><h2 id="📊-診斷評級-134-字" tabindex="-1">📊 診斷評級（134 字） <a class="header-anchor" href="#📊-診斷評級-134-字" aria-label="Permalink to &quot;📊 診斷評級（134 字）&quot;">​</a></h2><ul><li><strong>重點數據</strong>：CL 從 2024 Q4 低點 $264M 回升至 2025 Q4 $443M（+67.6%）。轉化率 79-86% 維持高檔。主要客戶佔營收 14%。</li><li><strong>診斷見解</strong>：CL 反轉印證下游需求脫離谷底，轉化率健康無訂單停滯。惟客戶集中度上升，需關注依賴風險。</li></ul><h2 id="🔍-答詢詳解-431-字" tabindex="-1">🔍 答詢詳解（431 字） <a class="header-anchor" href="#🔍-答詢詳解-431-字" aria-label="Permalink to &quot;🔍 答詢詳解（431 字）&quot;">​</a></h2><h3 id="訂單領先指標-合約負債與營收的動態對應" tabindex="-1">訂單領先指標：合約負債與營收的動態對應 <a class="header-anchor" href="#訂單領先指標-合約負債與營收的動態對應" aria-label="Permalink to &quot;訂單領先指標：合約負債與營收的動態對應&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2023 年 CL 擴張（Q1 $309M→Q4 $564M）領先 2024 H1 營收高峰。2024 年四季下滑至 Q4 $264M，2025 年 Q1 止跌回升至 Q4 $443M（+67.6%），領先營收於 Q3 轉正。兩者高度正相關。</li><li><strong>深度見解</strong>：2025 年 CL 增 $179M 列現金流入，2024 年減 $299M 為流出，方向反轉明確，下游需求已脫離谷底。</li></ul><h3 id="含金量分析-轉化效率與客戶品質" tabindex="-1">含金量分析：轉化效率與客戶品質 <a class="header-anchor" href="#含金量分析-轉化效率與客戶品質" aria-label="Permalink to &quot;含金量分析：轉化效率與客戶品質&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2024 年轉化率 86.1%（$485M/$564M），2025 年 79.0%（$209M/$264M）。略降主因下半年新收預付款未出貨。</li><li><strong>深度見解</strong>：轉化效率健康無違約。主要客戶佔 14%（$2.35B）較 2024 年增 22.4%，集中度風險上升。</li></ul><h3 id="能見度測算-短交期模式下的安全水位" tabindex="-1">能見度測算：短交期模式下的安全水位 <a class="header-anchor" href="#能見度測算-短交期模式下的安全水位" aria-label="Permalink to &quot;能見度測算：短交期模式下的安全水位&quot;">​</a></h3><ul><li><strong>核心重點</strong>：CL $443M / 日均營收 $53.3M = 8.3 天能見度，對比 2023 高峰 11.6 天仍偏低。</li><li><strong>深度見解</strong>：8 天對長交期產品不足但對 Cellular PA 屬常態。未揭露 LTA 金額可能低估實際訂單覆蓋。</li></ul><h2 id="💡-專家評析-361-字-≥2-個利空關鍵字" tabindex="-1">💡 專家評析（361 字，≥2 個利空關鍵字） <a class="header-anchor" href="#💡-專家評析-361-字-≥2-個利空關鍵字" aria-label="Permalink to &quot;💡 專家評析（361 字，≥2 個利空關鍵字）&quot;">​</a></h2><ol><li><p><strong>合約負債絕對金額偏低，緩衝空間有限</strong>：2025 年底合約負債 NT$443M 僅涵蓋 8 天營收，對比 2023 年高點 NT$564M（11.6 天）仍差距 27%。若終端需求再現下滑，合約負債可能在 1 季內快速萎縮至 NT$250M 以下（2024 年已見此模式），屆時將有 2-3 季的營收下滑壓力，緩衝期極短。</p></li><li><p><strong>主要客戶集中度上升，潛在轉單風險不可忽視</strong>：單一客戶（甲公司）佔 2025 年營收 14%（NT$2.35B），且金額持續擴大。砷化鎵產業近年面臨中國 IDM 廠（三安集成、卓勝微）產能擴張的競爭壓力，若客戶基於供應鏈安全考量分散下單至第二供應商，穩懋將面臨營收侵蝕風險。台灣同業全新光電（2455）亦持續擴產，競爭格局未見緩解。</p></li><li><p><strong>IFRS 15 合約負債侷限性：無法反映 LTA 覆蓋</strong>：穩懋為全球最大 GaAs 代工廠，與主要客戶簽訂長期供應合約（LTA）為產業慣例，但 LTA 的未執行部分不認列為合約負債（因不具有可強制執行之付款權利）。這意味著實際訂單能見度可能遠高於帳面合約負債所顯示的 8 天，資訊不對稱導致外部投資人難以精準評估，隱含預測風險。</p></li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：數據採集器.py (balance_sheet 3105)、(finance 3105)</li><li>原始數據：FinMind TaiwanStockBalanceSheet、TaiwanStockFinancialStatements</li><li>年報 PDF：2025_Q4_3105_合併.pdf（合約負債附註 p.64、主要客戶 p.82）</li><li>查詢參數：stock_id=3105, start=2023-01-01, end=2025-12-31</li><li>關鍵核對碼：2025/12/31 CL=NT$443,102K, 2024/12/31 CL=NT$264,338K, 轉化率 2024=86.1%, 2025=79.0%</li></ul>',19)])])}const g=l(i,[["render",o]]);export{u as __pageData,g as default};
